import{a as e,c as t,i as n,n as r,o as i,r as a,s as o,t as s}from"./app-X_Kuuhdi.js";var c=JSON.parse(`{"path":"/finance/berkshire-hathaway.html","title":"버크셔 해서웨이 (Berkshire Hathaway)","lang":"ko-KR","frontmatter":{"description":"버크셔 해서웨이 (Berkshire Hathaway) 버크셔 해서웨이(Berkshire Hathaway Inc.)는 워런 버핏(Warren Buffett)이 이끄는 미국의 다국적 지주회사(conglomerate)다. 뉴욕증권거래소(NYSE)에 BRK-A와 BRK-B 두 종류로 상장되어 있으며, 시가총액 기준 세계 최...","permalink":"/finance/berkshire-hathaway","head":[["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"버크셔 해서웨이 (Berkshire Hathaway)\\",\\"image\\":[\\"https://kmbzn.com/images/og.png\\"],\\"dateModified\\":\\"2026-06-12T15:12:24.000Z\\",\\"author\\":[]}"],["meta",{"property":"og:url","content":"https://kmbzn.com/finance/berkshire-hathaway"}],["meta",{"property":"og:title","content":"버크셔 해서웨이 (Berkshire Hathaway)"}],["meta",{"property":"og:description","content":"버크셔 해서웨이 (Berkshire Hathaway) 버크셔 해서웨이(Berkshire Hathaway Inc.)는 워런 버핏(Warren Buffett)이 이끄는 미국의 다국적 지주회사(conglomerate)다. 뉴욕증권거래소(NYSE)에 BRK-A와 BRK-B 두 종류로 상장되어 있으며, 시가총액 기준 세계 최..."}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:image","content":"https://kmbzn.com/images/og.png"}],["meta",{"property":"og:locale","content":"ko-KR"}],["meta",{"property":"og:updated_time","content":"2026-06-12T15:12:24.000Z"}],["meta",{"property":"article:modified_time","content":"2026-06-12T15:12:24.000Z"}]]},"git":{"createdTime":1781277144000,"updatedTime":1781277144000,"contributors":[{"name":"kmbzn","username":"kmbzn","email":"kmbzn24@gmail.com","commits":1,"url":"https://github.com/kmbzn"},{"name":"Claude Sonnet 4.6","username":"","email":"noreply@anthropic.com","commits":1}],"changelog":[{"hash":"867901d169b73496a8a67d2853b6d0b27bdbf876","time":1781277144000,"email":"kmbzn24@gmail.com","author":"kmbzn","message":"docs: rename all files to lowercase and add Products/Finance articles","coAuthors":[{"name":"Claude Sonnet 4.6","email":"noreply@anthropic.com"}]}]},"filePathRelative":"finance/berkshire-hathaway.md","autoDesc":true}`),l={name:`berkshire-hathaway.md`},u={class:`print-section`};function d(s,c,l,d,f,p){let m=t(`DateMeta`);return o(),a(`div`,null,[r(`section`,u,[c[0]||=r(`h1`,{id:`버크셔-해서웨이-berkshire-hathaway`,tabindex:`-1`},[r(`a`,{class:`header-anchor`,href:`#버크셔-해서웨이-berkshire-hathaway`},[r(`span`,null,`버크셔 해서웨이 (Berkshire Hathaway)`)])],-1),i(m),c[1]||=r(`p`,null,[e(`버크셔 해서웨이(Berkshire Hathaway Inc.)는 워런 버핏(Warren Buffett)이 이끄는 미국의 다국적 지주회사(conglomerate)다. 뉴욕증권거래소(NYSE)에 `),r(`strong`,null,`BRK-A`),e(`와 `),r(`strong`,null,`BRK-B`),e(` 두 종류로 상장되어 있으며, 시가총액 기준 세계 최대 기업 중 하나로 꼽힌다.`)],-1)]),c[2]||=n(`<section class="print-section"><h2 id="brk-a와-brk-b의-차이" tabindex="-1"><a class="header-anchor" href="#brk-a와-brk-b의-차이"><span>BRK-A와 BRK-B의 차이</span></a></h2><p>버크셔 해서웨이는 하나의 회사이지만 두 종류의 주식이 상장되어 있다. 두 주식은 동일한 회사의 소유권을 나타내지만 가격, 의결권, 분할 가능성에서 차이가 있다.</p><table><thead><tr><th>항목</th><th>BRK-A</th><th>BRK-B</th></tr></thead><tbody><tr><td>종류</td><td>Class A</td><td>Class B</td></tr><tr><td>주가 (2025년 기준)</td><td>약 $600,000~</td><td>약 $400~</td></tr><tr><td>의결권</td><td>1주 = 1표</td><td>1주 = 1/10,000 표 (BRK-A 기준)</td></tr><tr><td>경제적 권리</td><td>1주 = 1/1,500 배 of BRK-A</td><td>1주 = BRK-A의 1/1,500</td></tr><tr><td>주식 분할</td><td>1996년 이후 없음</td><td>2010년 50:1 분할 (원래 1/30 이었음)</td></tr><tr><td>전환</td><td>BRK-A → BRK-B 가능</td><td>BRK-B → BRK-A 불가</td></tr></tbody></table></section><section class="print-section"><h3 id="brk-a의-높은-주가-의도" tabindex="-1"><a class="header-anchor" href="#brk-a의-높은-주가-의도"><span>BRK-A의 높은 주가 의도</span></a></h3><p>워런 버핏은 의도적으로 BRK-A 주식을 분할하지 않는다. 이유는 <strong>단기 투자자(투기꾼)를 걸러내기 위해서</strong>다. 주가가 매우 높으면 소액 단기 거래가 어려워지고, 장기 가치 투자자만 주주로 남게 된다는 철학이다.</p><p>1996년 소규모 투자자들을 위해 BRK-A의 1/30 가치로 BRK-B를 발행했으며, 2010년 Burlington Northern Santa Fe(BNSF) 인수 대가로 주주에게 BRK-B 50:1 분할을 실시해 현재 BRK-A의 1/1,500 가치가 되었다.</p><hr></section><section class="print-section"><h2 id="회사-개요" tabindex="-1"><a class="header-anchor" href="#회사-개요"><span>회사 개요</span></a></h2></section><section class="print-section"><h3 id="역사" tabindex="-1"><a class="header-anchor" href="#역사"><span>역사</span></a></h3><ul><li><strong>1839년</strong>: Berkshire Cotton Manufacturing으로 출발 (섬유 제조업)</li><li><strong>1955년</strong>: Berkshire Fine Spinning Associates + Hathaway Manufacturing 합병 → Berkshire Hathaway 탄생</li><li><strong>1962년</strong>: 워런 버핏, 주식 매입 시작</li><li><strong>1965년</strong>: 버핏, 경영권 확보 (이후 섬유 사업 축소·청산)</li><li><strong>1967년~</strong>: 보험사(GEICO 등) 인수, 지주회사로 전환</li><li><strong>1988년</strong>: 코카콜라 주식 대규모 매입 (현재까지 보유)</li><li><strong>2010년</strong>: BNSF 철도 인수 ($44억)</li><li><strong>2016년~</strong>: 애플 주식 매입 시작 (현재 최대 단일 주식 포지션)</li></ul><p>버핏은 섬유 회사인 버크셔를 인수한 것이 자신의 역대 최대 실수라고 고백한 바 있다. 그러나 그 이후 보험·에너지·철도·소비재 전반으로 포트폴리오를 다각화해 세계적인 투자회사로 변모시켰다.</p></section><section class="print-section"><h3 id="주요-자회사-100-보유" tabindex="-1"><a class="header-anchor" href="#주요-자회사-100-보유"><span>주요 자회사 (100% 보유)</span></a></h3><table><thead><tr><th>회사</th><th>업종</th></tr></thead><tbody><tr><td>GEICO</td><td>자동차 보험</td></tr><tr><td>Berkshire Hathaway Energy</td><td>에너지·유틸리티</td></tr><tr><td>BNSF Railway</td><td>화물 철도</td></tr><tr><td>General Re</td><td>재보험</td></tr><tr><td>Clayton Homes</td><td>조립주택</td></tr><tr><td>Precision Castparts</td><td>항공우주 부품</td></tr><tr><td>Duracell</td><td>배터리</td></tr><tr><td>Dairy Queen</td><td>프랜차이즈 외식</td></tr><tr><td>See&#39;s Candies</td><td>초콜릿</td></tr></tbody></table></section><section class="print-section"><h3 id="주요-주식-보유-포트폴리오-2024-2025년-기준-상위" tabindex="-1"><a class="header-anchor" href="#주요-주식-보유-포트폴리오-2024-2025년-기준-상위"><span>주요 주식 보유 포트폴리오 (2024~2025년 기준 상위)</span></a></h3><table><thead><tr><th>종목</th><th>비중</th><th>보유 이유</th></tr></thead><tbody><tr><td><strong>Apple (AAPL)</strong></td><td>최대 단일 포지션</td><td>&quot;소비자 충성도 최고 브랜드&quot;</td></tr><tr><td><strong>American Express (AXP)</strong></td><td>상위권</td><td>수십 년 보유</td></tr><tr><td><strong>Bank of America (BAC)</strong></td><td>상위권</td><td>금융 섹터 핵심</td></tr><tr><td><strong>Coca-Cola (KO)</strong></td><td>상위권</td><td>1988년부터 보유, 영구 보유 선언</td></tr><tr><td><strong>Chevron (CVX)</strong></td><td>중간</td><td>에너지 섹터</td></tr><tr><td><strong>Occidental Petroleum (OXY)</strong></td><td>35%+ 지분 보유</td><td>최근 대량 매입</td></tr></tbody></table><hr></section><section class="print-section"><h2 id="투자-방법" tabindex="-1"><a class="header-anchor" href="#투자-방법"><span>투자 방법</span></a></h2></section><section class="print-section"><h3 id="국내-증권사에서-brk-b-매수" tabindex="-1"><a class="header-anchor" href="#국내-증권사에서-brk-b-매수"><span>국내 증권사에서 BRK-B 매수</span></a></h3><p>BRK-A는 주당 수억 원 수준이므로 개인투자자는 사실상 BRK-B만 고려한다.</p><ol><li>해외 주식 서비스가 있는 증권사 선택 (미래에셋, 삼성, 키움 등)</li><li>해외 주식 계좌 개설</li><li>달러 환전</li><li>티커 <code>BRK-B</code> 검색 후 매수</li></ol></section><section class="print-section"><h3 id="isa-연금저축-계좌" tabindex="-1"><a class="header-anchor" href="#isa-연금저축-계좌"><span>ISA / 연금저축 계좌</span></a></h3><p>BRK-B는 미국 증시 직접 상장 주식이므로, <strong>ISA나 연금저축에서는 직접 매수가 불가하다.</strong> 이 계좌들은 국내 상장 ETF·펀드만 편입 가능하다.</p><p>BRK-B에 ISA를 통해 간접적으로 투자하려면, BRK-B를 포함한 미국 주식형 펀드나 ETF를 통하는 방법이 있다.</p></section><section class="print-section"><h3 id="세금" tabindex="-1"><a class="header-anchor" href="#세금"><span>세금</span></a></h3><p>해외 주식 매매차익은 연 250만원 초과분에 대해 <strong>22% 양도소득세</strong> 적용. 배당도 없으므로 배당소득세 고려 불필요.</p><hr></section><section class="print-section"><h2 id="brk-b-vs-s-p-500-etf-비교" tabindex="-1"><a class="header-anchor" href="#brk-b-vs-s-p-500-etf-비교"><span>BRK-B vs S&amp;P 500 ETF 비교</span></a></h2><table><thead><tr><th>항목</th><th>BRK-B</th><th>S&amp;P 500 ETF (VOO 등)</th></tr></thead><tbody><tr><td>분산 투자</td><td>수십 개 자회사 + 보험·철도</td><td>500개 기업</td></tr><tr><td>액티브/패시브</td><td>액티브 (버핏 판단)</td><td>패시브 (지수 추종)</td></tr><tr><td>배당</td><td>없음 (버핏이 배당 안 함)</td><td>있음 (VOO 연 약 1.3%)</td></tr><tr><td>운용보수</td><td>없음 (주식 직접 보유)</td><td>0.03%</td></tr><tr><td>성과 (장기)</td><td>S&amp;P 500 대비 유사하거나 약간 하회 (최근 10년)</td><td>지수 성과 그대로</td></tr><tr><td>최대 리스크</td><td>버핏 후계 불확실성</td><td>시장 전체 하락</td></tr></tbody></table><p>워런 버핏 본인도 &quot;내 재산의 90%는 S&amp;P 500 인덱스 펀드에, 나머지 10%는 단기국채에 투자하라&quot;고 유언에 밝힌 바 있다. BRK-B는 버핏의 투자 철학에 대한 신뢰를 사는 것이라고 볼 수 있다.</p><hr></section><section class="print-section"><h2 id="버핏의-투자-원칙-요약" tabindex="-1"><a class="header-anchor" href="#버핏의-투자-원칙-요약"><span>버핏의 투자 원칙 요약</span></a></h2><p>버크셔를 이해하려면 워런 버핏의 투자 철학을 이해해야 한다.</p><ol><li><strong>내가 이해하는 사업에만 투자한다</strong> (Circle of Competence)</li><li><strong>강력한 해자(moat)를 가진 기업</strong>: 브랜드, 네트워크 효과, 원가 우위, 전환비용</li><li><strong>장기 보유</strong>: &quot;영원히 보유할 주식이 아니면 10분도 보유하지 말라&quot;</li><li><strong>가격 대비 가치</strong>: 좋은 기업을 합리적 가격에 (좋은 기업에 좋은 가격은 거의 없다)</li><li><strong>현금 보유</strong>: 기회가 왔을 때 즉각 움직이기 위해 대규모 현금을 항상 유지</li></ol><p>버크셔는 2024년 기준 현금성 자산 $3,000억 이상을 보유하고 있으며, 버핏은 충분히 매력적인 인수 대상을 찾지 못하면 현금을 쌓아두는 것을 택한다.</p><hr><div class="hint-container warning"><p class="hint-container-title">투자 전 고려사항</p><p>워런 버핏(94세, 2025년 기준)과 찰리 멍거(2023년 사망)의 부재 또는 영향력 약화 후 버크셔의 운용 능력이 지금과 같을지는 불확실하다. 후계자 그레그 에이블(Greg Abel)이 이미 지명되어 있으나, &#39;버핏 프리미엄&#39;이 주가에 반영되어 있을 가능성을 고려해야 한다.</p></div></section>`,12)])}var f=s(l,[[`render`,d]]);export{c as _pageData,f as default};